					resolvedCode = parsed.code.trim();
				}
				if (parsed.details && typeof parsed.details === 'object') {
					resolvedDetails = parsed.details;
				}
			}
		}
		super(msg);
		this.code = resolvedCode;
		this.details = resolvedDetails;
	}
}

