import { request } from '@playwright/test';

const BASE_URL =
	process.env.OPENSESSION_E2E_WORKER_BASE_URL ||
	process.env.OPENSESSION_E2E_SERVER_BASE_URL ||
	process.env.BASE_URL ||
	'http://localhost:3000';

/**
 * Global setup: register the admin user before any tests run.
 * On self-hosted Docker, the first registered user becomes admin.
 */
async function globalSetup() {
	const ctx = await request.newContext({ baseURL: BASE_URL });

	const capsResp = await ctx.get('/api/capabilities');
	if (!capsResp.ok()) {
		console.warn(`Global setup: capabilities returned ${capsResp.status()}, skipping admin bootstrap`);
		await ctx.dispose();
		return;
	}
	const caps = (await capsResp.json()) as { auth_enabled?: boolean };
	if (!caps.auth_enabled) {
		console.log('Global setup: auth disabled, skipping admin bootstrap');
		await ctx.dispose();
		return;
	}

	// Register admin as the very first user
	const resp = await ctx.post('/api/auth/register', {
		data: {
			email: 'pw-admin@e2e.local',
			[REDACTED_CREDENTIAL]
			nickname: 'pw-admin',
		},
	});

	if (resp.ok()) {
		console.log('Global setup: admin user registered (first user = admin)');
	} else {
		const body = await resp.text();
		// "email already registered" is fine — means admin exists from a previous run
		if (body.includes('already')) {
			console.log('Global setup: admin user already exists');
		} else {
			console.warn(`Global setup: register returned ${resp.status()}: ${body}`);
		}
	}

	await ctx.dispose();
}

export default globalSetup;

